// src/components/StudentDashboard.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  listProjectsForStudent,
  createProject,
  listMeetingsForStudent,
  listReportsForStudent,
  submitReport,
  createMentorRequest,
  listAvailabilityForMentor,
} from "../api/resources";
import { getUserId } from "../api/users";
import logout from "../utils/logout";
import "./studentdashboard.css";

export default function StudentDashboard() {
  const navigate = useNavigate();
  const studentId = getUserId();
  const [activeTab, setActiveTab] = useState("dashboard");

  const [project, setProject] = useState(null);
  const [meetings, setMeetings] = useState([]);
  const [reports, setReports] = useState([]);

  // upload form
  const [uploadType, setUploadType] = useState("report");
  const [uploadTitle, setUploadTitle] = useState("");
  const [uploadDescription, setUploadDescription] = useState("");
  const [uploadFile, setUploadFile] = useState(null);
  const [uploadStatus, setUploadStatus] = useState("");

  // mentor selection
  const [selectedMentorId, setSelectedMentorId] = useState("");
  const [mentorSlots, setMentorSlots] = useState([]);

  useEffect(() => {
    if (!studentId) { navigate("/login"); return; }
    const load = async () => {
      const [projRes, meetRes, repRes] = await Promise.all([
        listProjectsForStudent(studentId),
        listMeetingsForStudent(studentId),
        listReportsForStudent(studentId),
      ]);
      setProject((projRes.data || [])[0] || null);
      setMeetings(meetRes.data || []);
      setReports(repRes.data || []);
    };
    load();
  }, [studentId, navigate]);

  const handleCreateProject = async (form) => {
    await createProject(form); // {title, description, objectives, timeline, resources, mentor_id}
    const projRes = await listProjectsForStudent(studentId);
    setProject((projRes.data || [])[0] || null);
    alert("Project submitted!");
  };

  const handleRequestMentor = async () => {
    if (!selectedMentorId) return alert("Choose a mentor first");
    await createMentorRequest({
      mentor_id: selectedMentorId,
      project_id: project?.id || null,
      project_title: project?.title || "",
    });
    alert("Mentor request sent!");
  };

  const handleLoadMentorSlots = async () => {
    if (!selectedMentorId) return;
    const res = await listAvailabilityForMentor(selectedMentorId);
    setMentorSlots(res.data || []);
  };

  const handleUpload = async (e) => {
    e.preventDefault();
    if (!uploadFile) return setUploadStatus("Please select a file");
    try {
      setUploadStatus("Uploading...");
      const formData = new FormData();
      formData.append("file", uploadFile);
      formData.append("title", uploadTitle);
      formData.append("description", uploadDescription);
      formData.append("type", uploadType);
      await submitReport(formData);
      const repRes = await listReportsForStudent(studentId);
      setReports(repRes.data || []);
      setUploadTitle(""); setUploadDescription(""); setUploadFile(null);
      setUploadStatus("Uploaded!");
    } catch (err) {
      setUploadStatus("Upload failed");
    }
  };

  return (
    <div className="student-dashboard">
      <div className="dashboard-header">
        <h1>Student Dashboard</h1>
        <button onClick={() => logout(navigate)}>Logout</button>
      </div>

      <div className="tabs">
        <button className={activeTab==='dashboard'?'active':''} onClick={()=>setActiveTab('dashboard')}>Dashboard</button>
        <button className={activeTab==='project'?'active':''} onClick={()=>setActiveTab('project')}>Project</button>
        <button className={activeTab==='meetings'?'active':''} onClick={()=>setActiveTab('meetings')}>Meetings</button>
        <button className={activeTab==='reports'?'active':''} onClick={()=>setActiveTab('reports')}>Reports</button>
        <button className={activeTab==='mentor'?'active':''} onClick={()=>setActiveTab('mentor')}>Mentor</button>
      </div>

      <div className="main-content">
        {activeTab === "project" && (
          <div className="projects-section">
            <h2>My Project</h2>
            {project ? (
              <div className="project-card">
                <h3>{project.title}</h3>
                <p><b>Status:</b> {project.status}</p>
                <p><b>Description:</b> {project.description}</p>
              </div>
            ) : (
              <div className="project-form">
                {/* Keep your original form UI; this is just a minimal stub */}
                {/* On submit -> call handleCreateProject(form) */}
              </div>
            )}
          </div>
        )}

        {activeTab === "meetings" && (
          <div className="meetings-section">
            <h2>Meetings</h2>
            {meetings.length === 0 ? <p>No meetings yet.</p> : (
              <div className="assignments-table">
                <table>
                  <thead><tr><th>Date</th><th>Time</th><th>Location</th><th>Topic</th><th>Status</th></tr></thead>
                  <tbody>
                    {meetings.map((m)=>(
                      <tr key={m.id}>
                        <td>{m.date}</td><td>{m.time}</td><td>{m.location}</td><td>{m.topic}</td><td>{m.status}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {activeTab === "reports" && (
          <div className="reports-section">
            <h2>Reports</h2>

            <form onSubmit={handleUpload} style={{marginBottom:16}}>
              <select value={uploadType} onChange={e=>setUploadType(e.target.value)}>
                <option value="report">Report</option>
                <option value="presentation">Presentation</option>
                <option value="other">Other</option>
              </select>
              <input value={uploadTitle} onChange={e=>setUploadTitle(e.target.value)} placeholder="Title" required />
              <input value={uploadDescription} onChange={e=>setUploadDescription(e.target.value)} placeholder="Description" />
              <input type="file" onChange={e=>setUploadFile(e.target.files[0])} />
              <button type="submit">Upload</button>
              {uploadStatus && <span style={{marginLeft:10}}>{uploadStatus}</span>}
            </form>

            {reports.length === 0 ? <p>No reports yet.</p> : (
              <div className="assignments-table">
                <table>
                  <thead><tr><th>Title</th><th>Type</th><th>Status</th><th>Submitted</th></tr></thead>
                  <tbody>
                    {reports.map((r)=>(
                      <tr key={r.id}>
                        <td>{r.title}</td><td>{r.type}</td><td>{r.status}</td><td>{r.submitted_at}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {activeTab === "mentor" && (
          <div className="mentor-section">
            <h2>Request a Mentor</h2>
            {/* Use your mentor list UI; when a mentor is chosen, setSelectedMentorId */}
            <div style={{display:'flex', gap:12, alignItems:'center'}}>
              <input placeholder="Enter Mentor ID" value={selectedMentorId}
                     onChange={(e)=>setSelectedMentorId(e.target.value)} />
              <button onClick={handleRequestMentor}>Send Request</button>
              <button onClick={handleLoadMentorSlots}>View Mentor Slots</button>
            </div>

            <div className="slot-grid" style={{marginTop:16}}>
              {mentorSlots.length === 0 ? <p>No slots</p> : mentorSlots.map(s=>(
                <div className={`slot-card ${s.status}`} key={s.id}>
                  <p><b>{s.day}</b> {s.start_time}-{s.end_time}</p>
                  {s.location && <p><b>Location:</b> {s.location}</p>}
                  <span style={{color: s.status==='booked' ? '#FF6B00' : '#4caf50'}}>
                    {s.status === 'booked' ? 'Booked' : 'Free'}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Keep your dashboard tab UI from old code */}
      </div>
    </div>
  );
}
